mapper.select:
SELECT
t1.id as taskId,
t1.task_code taskCode,
t1.required_completion_time requestDate,
t1.end_detection_time finishDate,
t2.report_code reportCode,
t2.state state,
t1.entrustment_id
FROM
test_task AS t1
LEFT JOIN test_report_record AS t2 ON t2.entrustment_id = t1.entrustment_id
WHERE 1=1

    and t1.dept_id = #{deptId}


    and t1.required_completion_time  <=   #{requestDate}


    and t1.end_detection_time  <=   #{finishDate}


    and t1.end_detection_time  <=   #{finishDate}


    and t1.receive_time  <=   #{startDate}


    and  t1.review_time  <=   #{stopDate}

ORDER BY t1.task_code DESC
